mapper.insert:
INSERT INTO private_message (
    message_id, sender_id, receiver_id, content, image_url, message_type, status, send_time
) VALUES (
    #{messageId}, #{senderId}, #{receiverId}, #{content}, #{imageUrl}, #{messageType}, #{status}, #{sendTime}
)

mapper.update:
UPDATE private_message
SET status = #{status}
WHERE message_id = #{messageId}

UPDATE private_message
SET status = 2
WHERE receiver_id = #{receiverId} 
  AND sender_id = #{senderId} 
  AND status = 1

UPDATE private_message
SET status = 0
WHERE message_id = #{messageId}

UPDATE private_message
SET status = 0, content = '[消息已撤回]', image_url = NULL
WHERE message_id = #{messageId}

